import { Kruskal } from 'https://cdn.skypack.dev/@mattiasdahl/kruskal';

function solve(n, edges, k) {
    // Sort edges by weight
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize parent array for Union-Find
    const parent = Array(n).fill(0).map((_, i) => i);

    // Helper function to find the root of a node
    function find(x) {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    // Helper function to union two nodes
    function union(x, y) {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX !== rootY) {
            parent[rootY] = rootX;
            return true;
        }
        return false;
    }

    // Kruskal's algorithm to find the minimum maximum edge weight
    let maxEdge = 0;
    let components = n;
    for (const [u, v, w] of edges) {
        if (components > k) {
            if (union(u, v)) {
                maxEdge = Math.max(maxEdge, w);
                components--;
            }
        } else {
            break;
        }
    }

    return maxEdge;
}
